#define HINA_MAIN_STAGING_SIZE    (4ull * 1024ull * 1024ull)
#define HINA_MAX_RESOURCE_SLOTS     32u
#define HINA_ZOMBIE_LIST_CAPACITY   256u   // Fixed capacity per-frame zombie list (no growth)
#define HINA_ZOMBIE_LIST_MASK       (HINA_ZOMBIE_LIST_CAPACITY - 1)  // Bitmask for O(1) index wrap
#define HINA_MAX_SUBMISSION_ITEMS   32u
#define HINA_MAX_SUBMISSION_WAITS   8u
#define HINA_QUEUE_COUNT            3u
#define HINA_CMD_POOL_INDEX_IMMEDIATE UINT32_MAX
#define HINA_DEFERRED_PAYLOAD_INIT  8u
#define HINA_STAGING_RETIRED_INIT   2u
#define HINA_FRAME_ARENA_SIZE       (64u * 1024u)
#define HINA_RP_CACHE_SIZE          32
// Dynamic state dirty bits (for avoiding redundant vkCmdSet* calls)
#define HINA_DYNAMIC_ALL_BITS             0x0Fu

// All pools have fixed maximum capacities. Memory is VM-reserved and committed
// on demand. Overflow asserts and crashes.
// - Scratch arena for frame-local temporaries
// - Freelist embedded in free slots (next_free field)
// Fixed maximum pool capacities (generous limits, assert on overflow)
#ifndef HINA_POOL_INIT_BUFFERS
#define HINA_POOL_INIT_BUFFERS            0u
#endif
#ifndef HINA_POOL_INIT_TEXTURES
#define HINA_POOL_INIT_TEXTURES           0u
#endif
