static VkSampleCountFlagBits hina_samples_to_vk(hina_sample_count s)
{
  // Bit-smear then isolate MSB
  s |= s >> 1;
  s |= s >> 2;
  s |= s >> 4;
  uint32_t highest = (uint32_t)(s - (s >> 1));
  return highest ? (VkSampleCountFlagBits)highest : VK_SAMPLE_COUNT_1_BIT;
}

static VkImageAspectFlags hina_aspect_from_format(VkFormat fmt)
{
  switch (fmt)
  {
  case VK_FORMAT_D24_UNORM_S8_UINT:
  case VK_FORMAT_D32_SFLOAT_S8_UINT:
  case VK_FORMAT_D16_UNORM_S8_UINT:
    return VK_IMAGE_ASPECT_DEPTH_BIT | VK_IMAGE_ASPECT_STENCIL_BIT;
  case VK_FORMAT_D32_SFLOAT:
  case VK_FORMAT_D16_UNORM:
  case VK_FORMAT_X8_D24_UNORM_PACK32:
    return VK_IMAGE_ASPECT_DEPTH_BIT;
  default:
    return VK_IMAGE_ASPECT_COLOR_BIT;
  }
}

static VkIndexType hina_index_type_to_vk(hina_index_type t)
{
  return t == HINA_INDEX_UINT32 ? VK_INDEX_TYPE_UINT32 : VK_INDEX_TYPE_UINT16;
}

